def mode(nums):
    if not nums:
        return None
    counter = {}
    for num in nums:
        counter[num] = counter.get(num, 0) + 1
    max_count, result = max((value for key, value in counter.items()), key=lambda x:x[1])
    for num, count in counter.items():
        if count == max_count:
            if num < result:
                result = num
    return result
